def solve(packet: str) -> bool:
    # Correct packet format: FXN::<ver>::<channel>::<payload>::<checksum>
    # Checksum is sum of ASCII values of payload modulo 256.
    # Empty payload is allowed only for version 1 (assumed rule).

    def parse(pkt: str):
        parts = pkt.split("::")
        if len(parts) != 5 or parts[0] != "FXN":
            return None
        try:
            ver = int(parts[1])
            checksum = int(parts[4])
        except ValueError:
            return None
        return {
            "ver": ver,
            "channel": parts[2],
            "payload": parts[3],
            "checksum": checksum
        }

    def compute_checksum(payload: str, version: int) -> int:
        # simple sum of character codes modulo 256
        return sum(ord(c) for c in payload) % 256

    def is_valid(record: dict) -> bool:
        # version 1 allows empty payload; other versions require non-empty
        if record["ver"] != 1 and record["payload"] == "":
            return False
        expected = compute_checksum(record["payload"], record["ver"])
        return record["checksum"] == expected

    # 1. Try to parse the packet
    parsed = parse(packet)
    if parsed is None:
        return False

    # 2. Recompute correct checksum and rebuild packet
    correct_checksum = compute_checksum(parsed["payload"], parsed["ver"])
    rebuilt = f"FXN::{parsed['ver']}::{parsed['channel']}::{parsed['payload']}::{correct_checksum}"

    # 3. Parse the rebuilt packet and validate
    repaired = parse(rebuilt)
    if repaired is None:
        return False
    return is_valid(repaired)
