    """Parse a valid FXN packet and return a dict with keys ver, channel, payload, checksum."""
    parts = packet.split("::")
    if len(parts) != 5 or not parts[0].startswith("FXN"):
        raise ValueError("Invalid packet format")
    return {
        "ver": int(parts[1]),
        "channel": parts[2],
        "payload": parts[3],
        "checksum": int(parts[4])
    }

