    return (sum(ord(c) for c in payload) + ver) % 256

def fix_packet(packet: str) -> str:
    """Attempt to repair and recompute checksum. Returns fixed packet or original if unfixable."""
    try:
        rec = parse_fluxon_packet(packet)
        correct_cs = compute_fluxon_checksum(rec["payload"], rec["ver"])
        # Rebuild with correct checksum
        return f"FXN::{rec['ver']}::{rec['channel']}::{rec['payload']}::{correct_cs}"
    except Exception:
        # If packet cannot be parsed, return it unchanged (will not pass validation)
        return packet

