def solve(frames: list[str]) -> dict[str, float]:
    """
    Per channel, average the normalized token sums of valid framed packets.

    Args:
        frames: List of Fluxon frame strings, each like "[channel1:value1, channel2:value2, ...]"

    Returns:
        Dictionary mapping channel names to the average of their normalized token sums.
    """
    def decode_frame(frame: str) -> dict[str, float]:
        """Parse a frame into a dict mapping channel -> sum of raw values."""
        if not (frame.startswith('[') and frame.endswith(']')):
            raise ValueError("Invalid frame format")
        content = frame[1:-1].strip()
        if not content:
            return {}
        tokens = content.split(',')
        pairs = {}
        for token in tokens:
            token = token.strip()
            if ':' not in token:
                continue  # skip malformed token
            channel, value_str = token.split(':', 1)
            channel = channel.strip()
            try:
                value = float(value_str.strip())
            except ValueError:
                continue  # skip non‑numeric value
            pairs[channel] = pairs.get(channel, 0.0) + value
        return pairs

    def normalize(raw: float, channel: str) -> float:
        """Correct normalization: alpha/100, beta/10, others unchanged."""
        if channel == 'alpha':
            return raw / 100.0
        elif channel == 'beta':
            return raw / 10.0
        else:
            return raw

    channel_sums = defaultdict(list)

    for frame in frames:
        try:
            raw_dict = decode_frame(frame)
        except (ValueError, Exception):
            continue  # skip invalid frames
        if not raw_dict:
            continue
        for ch, raw_sum in raw_dict.items():
            normalized = normalize(raw_sum, ch)
            channel_sums[ch].append(normalized)

    result = {}
    for ch, vals in channel_sums.items():
        if vals:
            result[ch] = sum(vals) / len(vals)
    return result
