from typing import Any

def solve(series_list: list[str]) -> int:
    # Parse each JSON string into a series dict
    series = []
    for s in series_list:
        series.append(json.loads(s))

    # Collect all timestamps from all series
    all_ts = []
    for ser in series:
        all_ts.extend(ser["timestamps"])

    if not all_ts:
        return 0

    global_min = min(all_ts)
    sorted_ts = sorted(all_ts)
    n = len(sorted_ts)
    # Use lower median for even length
    median = sorted_ts[n // 2] if n % 2 == 1 else sorted_ts[n // 2 - 1]

    # Filter each series to the lower half [global_min, median]
    filtered = []
    for ser in series:
        new_ts = []
        new_vals = []
        for ts, val in zip(ser["timestamps"], ser["values"]):
            if global_min <= ts <= median:
                new_ts.append(ts)
                new_vals.append(val)
        filtered.append({"timestamps": new_ts, "values": new_vals})

    # Merge filtered series: first series wins on timestamp conflicts
    merged = {}
    for ser in filtered:
