import json
import statistics
from typing import Any

def _parse_series(series_str: str) -> dict[str, list]:
    """Parse a JSON string into a series dict with timestamps and values."""
    return json.loads(series_str)

def _merge_series(series_list: list[dict]) -> dict[str, list]:
    """Merge multiple series, first-wins on timestamp conflicts."""
    merged: dict[float, float] = {}
    for series in series_list:
        timestamps = series.get("timestamps", [])
        values = series.get("values", [])
        for ts, val in zip(timestamps, values):
            if ts not in merged:
                merged[ts] = val
    sorted_ts = sorted(merged)
    return {"timestamps": sorted_ts, "values": [merged[ts] for ts in sorted_ts]}

def _forecast_mean(series: dict) -> float:
    """Forecast using the mean of historical values."""
    values = series.get("values", [])
    if not values:
        return 0.0
    return statistics.mean(values)

def _forecast_diff(series: dict) -> float:
    """Forecast using the average difference (drift) of consecutive values."""
    values = series.get("values", [])
    if not values:
        return 0.0
    if len(values) == 1:
        return values[0]
    diffs = [values[i+1] - values[i] for i in range(len(values)-1)]
    avg_diff = statistics.mean(diffs)
    return values[-1] + avg_diff

