    """Parse all series, merge them, and return diff_forecast - mean_forecast."""
    parsed = [_parse_series(s) for s in series_list]
    merged = _merge_series(parsed)
    diff_forecast = _forecast_diff(merged)
    mean_forecast = _forecast_mean(merged)
    return diff_forecast - mean_forecast
